import json, re
from collections import Counter

filepath = '70aa7f36-7002-4f83-af6d-efc7eff30f3b.jsonl'

with open(filepath) as f:
    lines = f.readlines()

user_msgs = []
skills = []
mcp_tools = Counter()
write_files = []
edit_files = []
timestamps = []

for line in lines:
    try:
        obj = json.loads(line.strip())
        t = obj.get('type', '')

        # 用户消息
        if t == 'user':
            msg = obj.get('message', {})
            content = msg.get('content', '')
            if isinstance(content, str) and content.strip():
                # 排除 skill 注入的长内容
                if not content.startswith('Base directory for this skill'):
                    user_msgs.append(content.strip()[:500])
                else:
                    user_msgs.append('[skill context injection]')
            elif isinstance(content, list):
                texts = [c.get('text','') for c in content if isinstance(c, dict) and c.get('type') 
                combined = ' '.join(texts).strip()
                if combined and not combined.startswith('Base directory for this skill'):
                    user_msgs.append(combined[:500])
                elif combined:
                    user_msgs.append('[skill context injection]')

        # Skills (command-name)
        if isinstance(obj.get('message', {}).get('content', ''), str):
            matches = re.findall(r'<command-name>(.*?)</command-name>', obj['message']['content'])
            skills.extend(matches)
        if isinstance(obj.get('content', ''), str):
            matches = re.findall(r'<command-name>(.*?)</command-name>', obj['content'])
            skills.extend(matches)

        # 时间戳
        ts = obj.get('timestamp', '')
        if ts:
            timestamps.append(ts)

        # assistant 消息中的工具调用
        if t == 'assistant':
            msg = obj.get('message', {})
            content = msg.get('content', [])
            if isinstance(content, list):
                for item in content:
                    if isinstance(item, dict):
                        # MCP tools
                        if item.get('type') == 'tool_use':
                            name = item.get('name', '')
                            if name.startswith('mcp__'):
                                mcp_tools[name] += 1
                        # Write/Edit 工具
                        if item.get('name') == 'Write':
                            inp = item.get('input', {})
                            if inp.get('file_path'):
                                write_files.append(inp['file_path'])
                        if item.get('name') == 'Edit':
                            inp = item.get('input', {})
                            if inp.get('file_path'):
                                edit_files.append(inp['file_path'])

        # tool_result 类型
        if t == 'tool_result':
            pass

    except Exception as e:
        pass

# 提取 TODO 和待办事项
todos = []
for line in lines:
    try:
        obj = json.loads(line.strip())
        msg_str = json.dumps(obj, ensure_ascii=False)
        todo_matches = re.findall(r'(TODO|待办|FIXME|HACK|XXX|未完成)[：:]*\s*(.{5,80})', msg_str)
        todos.extend(todo_matches)
    except:
        pass

print('=== 文件 1: 70aa7f36 ===')
print(f'会话时间范围: {timestamps[0] if timestamps else \"N/A\"} ~ {timestamps[-1] if timestamps else \"N/
print(f'用户消息数量: {len([m for m in user_msgs if m != \"[skill context injection]\"])}')
print()
print('--- 用户消息 ---')
for i, m in enumerate(user_msgs):
    if m != '[skill context injection]':
        print(f'  [{i+1}] {m[:300]}')
print()
print(f'--- Skills ---')
for s in skills:
    print(f'  {s}')
print()
print(f'--- MCP 工具调用统计 ---')
for tool, count in mcp_tools.most_common():
    print(f'  {tool}: {count}次')
if not mcp_tools:
    print('  (无)')
print()
print(f'--- 写入文件 ---')
for f in write_files:
    print(f'  {f}')
if not write_files:
    print('  (无)')
print()
print(f'--- 编辑文件 ---')
for f in edit_files:
    print(f'  {f}')
if not edit_files:
    print('  (无)')
print()
print(f'--- TODO/待办 ---')
for t in todos[:10]:
    print(f'  {t[0]}: {t[1]}')
if not todos:
    print('  (无)')
